import { Hono } from 'hono';
import { z } from 'zod';

const app = new Hono();

app.get('/task-velocity', async (c) => {
  // Simulated data for demonstration purposes
  const tasks = [
    { id: 1, completedAt: new Date('2023-10-01T08:00:00Z') },
    { id: 2, completedAt: new Date('2023-10-02T14:00:00Z') },
    // ... more tasks ...
  ];

  const today = new Date();
  const thirtyDaysAgo = new Date(today);
  thirtyDaysAgo.setDate(today.getDate() - 30);

  const taskVelocityData = {
    tasksCompletedPerDay: {},
    averageCycleTime: 0,
    wipCount: 0,
  };

  // Calculate tasks completed per day
  for (const task of tasks) {
    if (task.completedAt >= thirtyDaysAgo && task.completedAt <= today) {
      const date = task.completedAt.toISOString().split('T')[0];
      taskVelocityData.tasksCompletedPerDay[date] = (taskVelocityData.tasksCompletedPerDay[date] || 0) + 1;
    }
  }

  // Calculate average cycle time
  let totalCycleTime = 0;
  for (const task of tasks) {
    if (task.completedAt >= thirtyDaysAgo && task.completedAt <= today) {
      const cycleTime = task.completedAt.getTime() - task.createdAt.getTime();
      totalCycleTime += cycleTime;
    }
  }
  taskVelocityData.averageCycleTime = tasks.length > 0 ? totalCycleTime / tasks.length : 0;

  // Calculate WIP count
  for (const task of tasks) {
    if (task.completedAt >= thirtyDaysAgo && task.completedAt <= today) {
      const wipCount = tasks.filter(t => t.completedAt === null).length;
      taskVelocityData.wipCount = Math.max(taskVelocityData.wipCount, wipCount);
    }
  }

  return c.json(taskVelocityData);
});

export default app;

